import sys
from unittest.mock import patch

# Create a strict import guard that will FAIL if qdrant_client is imported
class StrictImportGuard:
    def __init__(self):
        self.qdrant_imported = False

    def __call__(self, name, *args, **kwargs):
        if name == 'qdrant_client':
            self.qdrant_imported = True
            raise ImportError('qdrant_client is NOT installed (test scenario)')
        return __builtins__.__import__(name, *args, **kwargs)

guard = StrictImportGuard()

# Test 1: Non-loopback should fail BEFORE import attempt
print("Test 1: Non-loopback host should fail BEFORE import")
with patch('builtins.__import__', side_effect=guard):
    from src.infrastructure.vector_store import qdrant_setup
    from src.infrastructure import config

    qdrant_setup._cfg = lambda: {'host': '0.0.0.0', 'http_port': 6333}

    try:
        qdrant_setup.get_qdrant_client()
        print("  ✗ FAIL: No exception raised")
    except config.ConfigError:
        if guard.qdrant_imported:
            print(f"  ✗ FAIL: Guard fired but import was attempted first")
        else:
            print(f"  ✓ PASS: ConfigError raised WITHOUT attempting import")
    except ImportError as e:
        print(f"  ✗ FAIL: ImportError (guard did not fire): {e}")

# Test 2: Loopback host should attempt import
